import{_ as l}from"./_plugin-vue_export-helper.cdc0426e.js";import{o as i,c as t,f as d}from"./app.5b5c8f59.js";const e={},a=d('<h2 id="软件工程的主要内容" tabindex="-1"><a class="header-anchor" href="#软件工程的主要内容" aria-hidden="true">#</a> 软件工程的主要内容</h2><ul><li>软件工程的基本概念</li><li>软件开发模型</li><li>软件开发各阶段的任务、技术、方法</li><li>传统方法、面向对象方法</li><li>软件工程管理</li><li>软件质量保证</li><li>软件工程环境</li></ul><p>软件工程绪论</p><p>软件与软件危机</p><p>软件工程学</p><p>传统软件工程和面向对象软件工程</p><p>软件工程的应用</p><p>计算机软件发展的三个时期及特点</p><table><thead><tr><th></th><th>程序设计</th><th>程序系统</th><th>软件工程</th></tr></thead><tbody><tr><td>软件的范畴</td><td>程序</td><td>程序及说明书</td><td>产品软件(项目软件)</td></tr><tr><td>主要程序设计语言</td><td>汇编语言及机器语言</td><td>高级语言</td><td>高级语言系统、程序设计语言</td></tr><tr><td>软件工作范围</td><td>程序编写</td><td>包括设计和测试</td><td>软件生存期</td></tr><tr><td>需求者</td><td>程序设计者本人</td><td>少数用于</td><td>市场用户</td></tr></tbody></table><h4 id="什么是软件" tabindex="-1"><a class="header-anchor" href="#什么是软件" aria-hidden="true">#</a> 什么是软件？</h4><p>软件 = 程序 + 数据结构 + 文档</p><ul><li>程序：按照实现设计的功能和性能需求执行的指令序列</li><li>数据：是程序能够正常执行所需要的数据</li><li>与程序开发、维护和使用有关的图文材料</li></ul><h4 id="软件的特征" tabindex="-1"><a class="header-anchor" href="#软件的特征" aria-hidden="true">#</a> 软件的特征</h4><ul><li>软件是逻辑的，非物理的</li><li>与硬件特征的区别 <ul><li>开发方面</li><li>生产方面</li><li>维护方面</li></ul></li></ul><h4 id="软件危机" tabindex="-1"><a class="header-anchor" href="#软件危机" aria-hidden="true">#</a> 软件危机</h4><p>定义：计算机软件开发和维护过程中所遇到的一系列严重问题</p><p>主要特征：</p><ol><li>对软件开发成本和进度的估算很不准确</li><li>用户很不满意</li><li>质量很不可靠</li><li>没有适当的文档</li><li>软件成本比重上升</li><li>供不应求，软件开发生产率跟不上计算机应用深入的趋势</li></ol><p>原因：</p><ul><li>客观：软件本身特点 <ul><li>逻辑部件</li><li>规模庞大</li></ul></li><li>主观：不正确的开发方法 <ul><li>忽视需求分析</li><li>错误认为：软件开发 = 程序编写</li><li>轻视软件维护</li></ul></li></ul><p>解决方法：</p><ul><li>组织管理 <ul><li>工程项目管理方法</li></ul></li><li>技术措施 <ul><li>软件开发技术与方法</li><li>软件工具</li></ul></li></ul><h3 id="什么是软件工程" tabindex="-1"><a class="header-anchor" href="#什么是软件工程" aria-hidden="true">#</a> 什么是软件工程</h3><ul><li><p>软件工程是指导计算机软件开发和维护的工程学科。它采用工程的概念、原理、技术和方法来开发与维护软件，把经过时间考验而证明正确的管理技术和当前能够得到的最好的技术方法结合起来。</p></li><li><p>软件工程是一门涉及软件计划、需求分析、设计、编码、测试和维护的原理、方法及工具的研究和应用的学科。</p></li></ul><h3 id="软件工程的基本原理" tabindex="-1"><a class="header-anchor" href="#软件工程的基本原理" aria-hidden="true">#</a> 软件工程的基本原理</h3><ul><li><p>1968年在联邦德国召开的国际会议上正式提出“软件工程”术语。</p></li><li><p>目前有100多条关于软件工程的准则，其中最出名的是美国著名软件工程专家B.W.Boehm在1983年提出的7条基本原理。即软件工程准则。</p><ul><li><p>用分阶段的生命周期计划严格管理</p><p>经统计表明，不成功的软件项目中有一半左右是由于计划不周造成的。</p><p>Boehm认为，在软件的整个生命周期中应制定并严格执行六类计划：</p><ul><li>项目概要计划、</li><li>里程碑计划、</li><li>项目控制计划、</li><li>产品控制计划、</li><li>验证计划、</li><li>运行维护计划</li></ul></li><li><p>坚持进行阶段评审</p><ul><li>大部分错误是在编码之前造成的</li><li>错误发现与改正得越晚，所需付出的代价越高。</li></ul><p>因此，在每个阶段都进行严格的评审，以便尽早发现在软件开发过程的错误</p></li><li><p>实行严格的产品控制</p><ul><li>在软件开发过程中不要随意改变需求，因为改变某项需求往往需要付出较高的代价，但在实践中用户往往会提出需求变更，因此需要采取科学的产品控制技术。</li><li>目前主要实行基准配置管理：<strong>基准配置</strong>是指经过阶段评审后的软件配置成分，如各个阶段产生的文档或程序代码。</li><li>对涉及基准配置的修改，必须经过严格的评审，通过后才能实施修改。</li></ul></li><li><p>采用现代程序设计技术</p><ul><li>实践表明：采用先进的技术既可提高软件开发的效率，又可提高软件维护的效率。</li><li>80年代及之前：结构化分析、设计技术</li><li>90年代：面向对象分析、设计技术</li></ul></li></ul></li></ul>',26),r=[a];function h(p,u){return i(),t("div",null,r)}const s=l(e,[["render",h],["__file","se-intro.html.vue"]]);export{s as default};
